with open('data/computer_1.json', encoding='utf-8') as f:
    data = json.load(f)

updated = 0
for q in data:
    if q['date'] == '20161022' and q['id'] in EXPLANATIONS:
        q['explanation'] = EXPLANATIONS[q['id']]
        updated += 1

with open('data/computer_1.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f'완료: {updated}개 문항 해설 추가')
